210: // Information about a range of character for tone positioning.
211: const Pseudoword = struct {
212:     // The start position of the word on State.buffer_effective.
213:     start: u8,
214:     // The end position of the word on State.buffer_effective.
215:     end: u8,
216:     // The start position of the vowels on State.buffer_effective.
217:     vowels_start: ?u8,
218:     // The end position of the vowels on State.buffer_effective.
219:     vowels_end: ?u8,
220:     // The length of the word.
221:     length: u8,
222: 
223:     fn has_vowels(self: *const Pseudoword) bool {
224:         return self.vowels_start != null and self.vowels_end != null;
225:     }
226: };
