946:         var word_start: ?u8 = null;
947:         var vowels_start: ?u8 = null;
948:         var vowels_end: ?u8 = null;
949:         var index: u8 = self.buffer_length;
950:         while (index > 0) {
951:             index -= 1;
952:             const sp = self.buffer_effective[index];
953:             const is_vowel = switch (std.ascii.toUpper(sp.base)) {
954:                 'A', 'E', 'I', 'O', 'U', 'Y' => true,
955:                 else => false,
956:             };
957:             const is_consonant = !is_vowel;
958: 
959:             // Found vowel for the first time, mark end of vowels.
960:             if (is_vowel and vowels_end == null) {
961:                 vowels_end = index;
962: 
963:                 if (index == 0) {
