965:                     word_start = index;
966:                     break;
967:                 }
968:             } else if (is_consonant and vowels_end != null and vowels_start == null) {
969:                 // Found consonant after the vowels (reverse).
970:                 // 1. Set the previous index to vowels_start.
971:                 vowels_start = index + 1;
