979:                 word_start = index;
980:                 break;
981:             } else if (index == 0 and is_consonant and vowels_end == null and vowels_start == null) {
982:                 // No vowels found, only consonants.
983:                 word_start = index;
984:                 break;
985:             }
986:         }
987:         const word_end: u8 = self.buffer_length - 1;
988: 
989:         // word_start must always have valid values.
990:         assert(word_start != null);
991:         assert(word_start.? <= word_end);
